import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.CvgP6Fyv.js";const v=JSON.parse('{"title":"Articles","description":"","frontmatter":{},"headers":[],"relativePath":"posts/index.md","filePath":"posts/index.md","lastUpdated":1777889597000}'),n={name:"posts/index.md"};function r(c,e,l,o,d,m){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="articles" tabindex="-1">Articles <a class="header-anchor" href="#articles" aria-label="Permalink to &quot;Articles&quot;">​</a></h1><div class="article-index"><div class="category-section"><h2>Quantum Mechanics Notes</h2><ul class="article-list"><li class="article-item"><span class="article-date">2026-05-03</span><div><div class="article-title"><a href="./quantum-mechanics/electron-proton-elastic-scattering">From Mott Scattering to the Rosenbluth Formula: Electron-Proton Elastic Scattering</a></div><div class="article-desc">Complete derivation of the Rosenbluth formula from QED first principles: electron and hadronic tensor trace calculations, form factor parameterization, and the pointlike limit</div></div></li><li class="article-item"><span class="article-date">2026-04-04</span><div><div class="article-title"><a href="./quantum-mechanics/angular-momentum-algebra">Angular Momentum Algebra: From Commutation Relations to Addition of Angular Momenta</a></div><div class="article-desc">Angular momentum commutation relations, ladder operators and eigenvalue spectrum, matrix representations for spin-1/2 and spin-1, and Clebsch-Gordan coefficients for angular momentum addition</div></div></li><li class="article-item"><span class="article-date">2026-04-02</span><div><div class="article-title"><a href="./quantum-mechanics/bound-states-resonances-scattering">Bound States, Resonances, and Scattering: Three Pillars of Quantum Mechanics</a></div><div class="article-desc">Existence conditions for bound states in 1D/3D potentials, resonance states and the Breit-Wigner formula, scattering theory with partial wave analysis and Levinson&#39;s theorem</div></div></li><li class="article-item"><span class="article-date">2026-03-31</span><div><div class="article-title"><a href="./quantum-mechanics/time-dependent-perturbation-theory">Time-Dependent Perturbation Theory: From Fermi&#39;s Golden Rule to Linear Response</a></div><div class="article-desc">Interaction picture, Dyson series, Fermi&#39;s Golden Rule, scattering theory with Lippmann-Schwinger equation, and linear response theory with Kubo formula</div></div></li><li class="article-item"><span class="article-date">2026-03-30</span><div><div class="article-title"><a href="./quantum-mechanics/stationary-perturbation-theory">Stationary Perturbation Theory: Non-Degenerate vs Degenerate Cases</a></div><div class="article-desc">Complete derivation of energy corrections up to third order and wavefunction corrections up to second order for non-degenerate perturbation theory, with detailed discussion of degenerate case</div></div></li></ul></div><div class="category-section"><h2>Statistical Mechanics Notes</h2><ul class="article-list"><li class="article-item"><span class="article-date">2026-05-03</span><div><div class="article-title"><a href="./statistical-mechanics/quantum-dice-and-coins">Quantum Dice and Coins: A Gentle Introduction to Bose-Einstein and Fermi-Dirac Statistics</a></div><div class="article-desc">Sethna Exercise 1.1 — mapping quantum statistics onto dice games, from Pauli exclusion to Bose-Einstein condensation in the thermodynamic limit</div></div></li></ul></div><div class="category-section"><h2>Condensed Matter Notes</h2><ul class="article-list"><li class="article-item"><span class="article-date">2026-05-03</span><div><div class="article-title"><a href="./condensed-matter/specular-andreev-reflection-graphene">Specular Andreev Reflection in Graphene: From Dirac Fermions to Superconducting Proximity</a></div><div class="article-desc">Dirac-Bogoliubov-de Gennes theory for graphene NS junctions, boundary condition matching, retro-reflection versus specular reflection, and conductance inversion at the Dirac point</div></div></li><li class="article-item"><span class="article-date">2026-04-04</span><div><div class="article-title"><a href="./condensed-matter/crystal-structures-bravais-lattices">Crystal Structures: From Bravais Lattices to Reciprocal Space</a></div><div class="article-desc">Seven crystal systems, fourteen Bravais lattices, Wigner-Seitz cell construction, reciprocal lattice derivation, and first Brillouin zone</div></div></li><li class="article-item"><span class="article-date">2026-04-04</span><div><div class="article-title"><a href="./condensed-matter/electron-energy-bands-origin">Electron Energy Bands: From Atomic Orbitals to Bloch States</a></div><div class="article-desc">Origin of energy bands from wavefunction overlap, LCAO approximation, exact solution of Kronig-Penney model, and proof of Bloch&#39;s theorem</div></div></li><li class="article-item"><span class="article-date">2026-04-03</span><div><div class="article-title"><a href="./condensed-matter/spontaneous-symmetry-breaking">Spontaneous Symmetry Breaking: From Functional Calculus to Goldstone Modes</a></div><div class="article-desc">Functional differentiation vs ordinary calculus, spontaneous symmetry breaking in condensed matter, Goldstone&#39;s theorem, and order parameter physics</div></div></li><li class="article-item"><span class="article-date">2026-04-02</span><div><div class="article-title"><a href="./condensed-matter/metal-electron-theory-fermi-statistics-transport">Metal Electron Theory: From Fermi Statistics to Transport Properties</a></div><div class="article-desc">Fermi-Dirac statistics, electronic heat capacity, Boltzmann transport equation, conductivity, Hall effect, and thermoelectric effects in metals</div></div></li><li class="article-item"><span class="article-date">2026-04-02</span><div><div class="article-title"><a href="./condensed-matter/semiconductor-electron-theory">Semiconductor Electron Theory: From Band Structure to p-n Junctions</a></div><div class="article-desc">Direct and indirect band gaps, Maxwell-Boltzmann statistics for carriers, doping and impurity levels, transport properties, and p-n junction physics</div></div></li><li class="article-item"><span class="article-date">2026-03-31</span><div><div class="article-title"><a href="./condensed-matter/green-functions-quantum-transport">Green&#39;s Functions in Condensed Matter: From Equilibrium to Non-Equilibrium Quantum Transport</a></div><div class="article-desc">Single-particle and many-body Green&#39;s functions, Matsubara formalism, Dyson equation, Keldysh non-equilibrium technique, and applications to quantum transport</div></div></li><li class="article-item"><span class="article-date">2026-03-31</span><div><div class="article-title"><a href="./condensed-matter/phonons-lattice-dynamics">Phonons: From Classical Lattice Dynamics to Quantum Transport</a></div><div class="article-desc">Classical and quantum treatment of lattice vibrations, acoustic and optical phonons, van Hove singularities, and polaritons in ionic crystals</div></div></li></ul></div><div class="tag-list"><span class="tag">research-notes</span></div></div>',2)])])}const p=t(n,[["render",r]]);export{v as __pageData,p as default};
